def main():
 a=argparse.ArgumentParser();a.add_argument('--input_json',required=True);a.add_argument('--output_dir',required=True);a.add_argument('--name',default='perfect_concept_set_v1');a.add_argument('--target_total',type=int,default=120);x=a.parse_args()
 src=Path(x.input_json);out=Path(x.output_dir);out.mkdir(parents=True,exist_ok=True);d=json.loads(src.read_text())
